SELECT dblink_connect('argus_conn', 'host=localhost port=5432 dbname=argus user=argus');
SET session_replication_role = 'replica';


-- child tables

SET session_replication_role = 'origin';

-- Update admin branding
UPDATE users SET
  email = REPLACE(email, '@argus.local', '@digicap.local'),
  password_hash = crypt('digicap1234!', gen_salt('bf'))
WHERE username = 'admin' AND email LIKE '%@argus.local';

SELECT dblink_disconnect('argus_conn');
